import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme(); // Consuming your ThemeContext
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  /* ───────── 1. API Synchronization ───────── */
  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      const data = Array.isArray(res.data) ? res.data : [];
      setHistory(data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE: UNABLE_TO_REACH_DATABASE");
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: This node data will be destroyed. Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("DATA_PURGED_SUCCESSFULLY");
    } catch (err) {
      toast.error("PURGE_ERROR: SYSTEM_LOCK_ACTIVE");
    }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Strategy_Node_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("EXPORT_FAILED: PDF_GENERATION_ERROR");
    }
  };

  useEffect(() => {
    fetchHistory();
  }, [fetchHistory]);

  /* ───────── 2. React-Based Layout Mapping ───────── */
  // We use useMemo to force a re-render of styles when isDark changes
  const dynamicTheme = useMemo(() => ({
    overlay: isDark ? 'rgba(0, 0, 0, 0.96)' : 'rgba(255, 255, 255, 0.92)',
    cardBg: isDark ? '#000000' : 'var(--bg-input, #ffffff)'
  }), [isDark]);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_CORE_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      {/* ── Page Header ── */}
      <div style={headerRow}>
        <div style={titleGroup}>
          <Archive size={28} color="var(--accent-primary)"/>
          <h2 style={headerStyle}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES_STORED</span>
      </div>

      {/* ── List of Strategy Nodes ── */}
      <div style={listStyle}>
        {history.length === 0 ? (
          <div style={emptyState}>NO_DATA_FOUND: INITIALIZE_STRATEGY_CORE</div>
        ) : (
          history.map((item) => (
            <div key={item.id} className="vault-card" style={{...cardStyle, background: dynamicTheme.cardBg}}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={metaText}><Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={14}/> RISK: {item.risk_score}</span>
                </div>
                <h4 style={titleStyle}>{item.goal}</h4>
              </div>

              <div style={actionColumn}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View Details"><Eye size={20}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Export PDF"><Download size={20}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Purge Record"><Trash2 size={20}/></button>
              </div>
            </div>
          ))
        )}
      </div>

      {/* ── OLED Theme-Aware Modal ── */}
      {selectedItem && (
        <div style={{...modalOverlay, background: dynamicTheme.overlay}}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={24}/></button>
            </div>
            
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              
              <div className="markdown-vault">
                <p style={labelSmall}><AlignLeft size={14}/> STRATEGIC_SUMMARY</p>
                <div style={widgetBox}>
                  <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>

                <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div style={widgetBox}>
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        /* Syncing Markdown with theme variables */
        .markdown-vault p { color: var(--text-primary); font-size: 0.95rem; line-height: 1.6; margin-bottom: 1rem; }
        .markdown-vault h1, .markdown-vault h2 { color: var(--accent-primary); font-size: 1.1rem; margin-bottom: 0.5rem; text-transform: uppercase; font-weight: 800; }
        
        .vault-card { transition: all 0.2s ease; border: 1px solid var(--surface-border); border-radius: 16px; }
        .vault-card:hover { border-color: var(--accent-primary) !important; transform: translateY(-2px); }
        
        .reveal-node { animation: fadeIn 0.4s ease-out; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

/* ─────────────────────────────── Systematic Styles ─────────────────────────────── */

const containerStyle = { 
    padding: '3rem 1.5rem', 
    maxWidth: '1000px', 
    margin: '0 auto', 
    background: 'var(--bg-primary)', // Direct sync with theme.js
    minHeight: '100vh' 
};

const headerRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '3rem', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1.2rem' };
